#include<bits/stdc++.h>
using namespace std;
long long n,m;
char a[1010][1010];
long long id(long long x,long long y)
{
    return (x-1)*m+y;
}
long long fa[1500010],dp[1500010];
long long find(long long x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(long long x,long long y)
{
    fa[find(x)]=find(y);
}
const long long mod=1e9+7;
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
        for(long long j=1;j<=m;j++)
        {
            fa[id(i,j)]=id(i,j);
            dp[id(i,j)]=1;
        }
    }
    for(long long i=n-1;i>=1;i--)
    {
        for(long long j=3;j<m;j++)
        {
            if(a[i][j]=='.'&&a[i][j-1]=='.')
            {
                merge(id(i,j),id(i,j-1));
            }
        }
        for(long long j=2;j<m;j++)
        {
            if(a[i][j]=='.'&&a[i+1][j]=='.')
            {
                long long x=find(id(i,j)),y=find(id(i+1,j));
                if(x!=y)
                {
                    merge(y,x);
                    dp[x]=dp[x]*dp[y]%mod;
                }
            }
        }
        for(long long j=2;j<m;j++)
        {
            if(a[i][j]=='.'&&find(id(i,j))==id(i,j))
            {
                dp[id(i,j)]++;
                dp[id(i,j)]%=mod;
            }
        }
    }
    long long ans=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            if(a[i][j]=='.'&&find(id(i,j))==id(i,j))
            {
                ans*=dp[id(i,j)];
                ans%=mod;
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
